<?php session_start(); require 'includes/header.php'; require_login(); if($_SERVER['REQUEST_METHOD']==='POST' && can_manage()){ $pdo->prepare('INSERT INTO categories(name,description) VALUES(?,?)')->execute([$_POST['name'],$_POST['description']]); header('Location:categories.php'); exit; } $rows=$pdo->query('SELECT * FROM categories ORDER BY name')->fetchAll(); ?><h1>Categories</h1><div class="card"><form method="post"><input name="name" placeholder="Category Name" required><textarea name="description" placeholder="Description"></textarea><button>Save Category</button></form></div><div class="card"><table><tr><th>Name</th><th>Description</th></tr><?php foreach($rows as $r): ?><tr><td><?=e($r['name'])?></td><td><?=e($r['description'])?></td></tr><?php endforeach ?></table></div><?php require 'includes/footer.php'; ?>
